import strawberry
from strawberry.fastapi import GraphQLRouter
from fastapi import FastAPI
from typing import List, Optional
from datetime import datetime
from dataclasses import field
import asyncio

# ── Types ───────────────────────────────────────────────
@strawberry.type
class User:
    id: strawberry.ID
    name: str
    email: str
    created_at: datetime


@strawberry.type
class Post:
    id: strawberry.ID
    title: str
    content: str
    author_id: strawberry.ID
    published: bool
    created_at: datetime


@strawberry.type
class PostConnection:
    items: List[Post]
    total: int
    has_more: bool


@strawberry.input
class CreatePostInput:
    title: str
    content: str
    published: bool = False


@strawberry.input
class UpdatePostInput:
    title: Optional[str] = None
    content: Optional[str] = None
    published: Optional[bool] = None


# ── In-memory storage ──────────────────────────────────
users_db = {
    "1": User(id="1", name="John Doe", email="john@example.com", created_at=datetime.now()),
    "2": User(id="2", name="Jane Smith", email="jane@example.com", created_at=datetime.now()),
}
posts_db = {
    "1": Post(id="1", title="First Post", content="Hello World", author_id="1", published=True, created_at=datetime.now()),
    "2": Post(id="2", title="Draft Post", content="Work in progress", author_id="1", published=False, created_at=datetime.now()),
}
next_id = 3


# ── DataLoader for N+1 prevention ───────────────────────
class DataLoader:
    def __init__(self):
        self.cache = {}

    async def load(self, key: str):
        if key in self.cache:
            return self.cache[key]
        # Simulate batch loading
        result = users_db.get(key)
        self.cache[key] = result
        return result

user_loader = DataLoader()


# ── Resolvers ───────────────────────────────────────────
@strawberry.type
class Query:
    @strawberry.field
    async def user(self, id: strawberry.ID) -> Optional[User]:
        return users_db.get(id)

    @strawberry.field
    async def users(self) -> List[User]:
        return list(users_db.values())

    @strawberry.field
    async def post(self, id: strawberry.ID) -> Optional[Post]:
        return posts_db.get(id)

    @strawberry.field
    async def posts(
        self,
        author_id: Optional[strawberry.ID] = None,
        published_only: bool = False,
        limit: int = 10,
        offset: int = 0
    ) -> PostConnection:
        items = list(posts_db.values())

        if author_id:
            items = [p for p in items if p.author_id == author_id]

        if published_only:
            items = [p for p in items if p.published]

        total = len(items)
        items = items[offset:offset + limit]

        return PostConnection(
            items=items,
            total=total,
            has_more=(offset + limit) < total
        )


@strawberry.type
class Mutation:
    @strawberry.mutation
    async def create_post(self, input: CreatePostInput) -> Post:
        global next_id
        post = Post(
            id=strawberry.ID(str(next_id)),
            title=input.title,
            content=input.content,
            author_id="1",
            published=input.published,
            created_at=datetime.now()
        )
        posts_db[str(next_id)] = post
        next_id += 1
        return post

    @strawberry.mutation
    async def update_post(
        self,
        id: strawberry.ID,
        input: UpdatePostInput
    ) -> Optional[Post]:
        post = posts_db.get(id)
        if not post:
            return None

        if input.title is not None:
            post.title = input.title
        if input.content is not None:
            post.content = input.content
        if input.published is not None:
            post.published = input.published

        return post

    @strawberry.mutation
    async def delete_post(self, id: strawberry.ID) -> bool:
        if id in posts_db:
            del posts_db[id]
            return True
        return False


# ── Schema and App ──────────────────────────────────────
schema = strawberry.Schema(query=Query, mutation=Mutation)
graphql_app = GraphQLRouter(schema)

app = FastAPI(title="GraphQL API Example")
app.include_router(graphql_app, prefix="/graphql")
